import{f as s,o as a,c as t,a2 as e}from"./chunks/framework.Ccw_j35p.js";const b=JSON.parse('{"title":"敏捷开发","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/agile.md","filePath":"software-engineering/agile.md","lastUpdated":1780925082000}'),r={name:"software-engineering/agile.md"};function p(l,n,i,o,d,c){return a(),t("div",null,[...n[0]||(n[0]=[e(`<h1 id="敏捷开发" tabindex="-1">敏捷开发 <a class="header-anchor" href="#敏捷开发" aria-label="Permalink to &quot;敏捷开发&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识模块</th><th>重点内容</th><th>面试频率</th></tr></thead><tbody><tr><td>Scrum 框架</td><td>3 角色（PO/SM/Team）、5 事件（Sprint、Daily Scrum、Review、Retro、Planning）</td><td>极高</td></tr><tr><td>Kanban 方法</td><td>可视化工作流、WIP 限制、累积流图、与 Scrum 的区别</td><td>高</td></tr><tr><td>用户故事</td><td>INVEST 原则、拆分技巧、验收标准（AC）</td><td>极高</td></tr><tr><td>Sprint 计划</td><td>容量规划、故事点估算、速率（Velocity）</td><td>高</td></tr><tr><td>持续改进</td><td>回顾会议技巧、5 Why 分析法、改进看板</td><td>中高</td></tr><tr><td>敏捷 vs 瀑布</td><td>核心理念差异、适用场景对比</td><td>高</td></tr></tbody></table><hr><h2 id="一、敏捷开发的核心思想" tabindex="-1">一、敏捷开发的核心思想 <a class="header-anchor" href="#一、敏捷开发的核心思想" aria-label="Permalink to &quot;一、敏捷开发的核心思想&quot;">​</a></h2><h3 id="_1-1-敏捷不是-快" tabindex="-1">1.1 敏捷不是&quot;快&quot; <a class="header-anchor" href="#_1-1-敏捷不是-快" aria-label="Permalink to &quot;1.1 敏捷不是&quot;快&quot;&quot;">​</a></h3><p>敏捷（Agile）常被误解为&quot;快速交付&quot;。敏捷的真正核心是<strong>快速响应变化</strong>——接受需求会变化这一事实，建立能够灵活应对变化的开发节奏和组织结构。</p><div class="tip custom-block"><p class="custom-block-title">面试金句</p><p>&quot;敏捷不是让你跑得更快，而是让你在方向错误时能更早地发现并转向。敏捷的核心是<strong>反馈循环</strong>（Feedback Loop）——越早获得反馈，纠偏成本越低。&quot;</p></div><h3 id="_1-2-敏捷宣言" tabindex="-1">1.2 敏捷宣言 <a class="header-anchor" href="#_1-2-敏捷宣言" aria-label="Permalink to &quot;1.2 敏捷宣言&quot;">​</a></h3><blockquote><p><strong>个体和互动</strong> 高于 流程和工具 <strong>可工作的软件</strong> 高于 详尽的文档 <strong>客户合作</strong> 高于 合同谈判 <strong>响应变化</strong> 高于 遵循计划</p></blockquote><p>虽然右项也有价值，但更重视左项的价值。</p><h3 id="_1-3-敏捷-vs-瀑布" tabindex="-1">1.3 敏捷 vs 瀑布 <a class="header-anchor" href="#_1-3-敏捷-vs-瀑布" aria-label="Permalink to &quot;1.3 敏捷 vs 瀑布&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>瀑布模型</th><th>敏捷开发</th></tr></thead><tbody><tr><td><strong>需求</strong></td><td>一次性确定，变更成本高</td><td>迭代演化，欢迎变化</td></tr><tr><td><strong>交付</strong></td><td>项目结束时一次性交付</td><td>每个 Sprint 交付可工作的增量</td></tr><tr><td><strong>反馈</strong></td><td>项目尾声才获得用户反馈</td><td>每个 Sprint 获取反馈并调整</td></tr><tr><td><strong>风险</strong></td><td>集中在后期暴露</td><td>持续暴露，早期化解</td></tr><tr><td><strong>适用场景</strong></td><td>需求明确且稳定（航天、医疗设备）</td><td>需求不确定或快速变化（互联网产品）</td></tr></tbody></table><hr><h2 id="二、scrum-框架" tabindex="-1">二、Scrum 框架 <a class="header-anchor" href="#二、scrum-框架" aria-label="Permalink to &quot;二、Scrum 框架&quot;">​</a></h2><p>Scrum 是最流行的敏捷框架，定义了角色、事件和工件三类核心要素。</p><h3 id="_2-1-三大角色" tabindex="-1">2.1 三大角色 <a class="header-anchor" href="#_2-1-三大角色" aria-label="Permalink to &quot;2.1 三大角色&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>职责</th><th>常见误解</th></tr></thead><tbody><tr><td><strong>Product Owner（PO）</strong></td><td>定义产品愿景、管理 Backlog 优先级、回答团队的业务疑问</td><td>PO 不是&quot;需求翻译机&quot;，而是产品的最终负责人</td></tr><tr><td><strong>Scrum Master（SM）</strong></td><td>确保 Scrum 流程被正确执行、消除团队障碍、引导会议</td><td>SM 不是&quot;项目经理&quot;，而是教练和仆人式领导者</td></tr><tr><td><strong>Development Team</strong></td><td>自组织地完成 Sprint 目标，交付可工作的软件增量</td><td>团队成员不是&quot;资源&quot;，理想规模 5-9 人</td></tr></tbody></table><h3 id="_2-2-五大事件" tabindex="-1">2.2 五大事件 <a class="header-anchor" href="#_2-2-五大事件" aria-label="Permalink to &quot;2.2 五大事件&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sprint（时间盒：1-4 周，通常 2 周）</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── Sprint Planning（Sprint 开始时，≤ 8 小时 / 月 Sprint）</span></span>
<span class="line"><span>│   ├── 议题 1：这个 Sprint 能交付什么？（PO 讲优先级）</span></span>
<span class="line"><span>│   └── 议题 2：如何完成这些工作？（团队拆解任务）</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── Daily Scrum（每天 ≤ 15 分钟，同一时间、同一地点）</span></span>
<span class="line"><span>│   ├── 昨天做了什么？</span></span>
<span class="line"><span>│   ├── 今天打算做什么？</span></span>
<span class="line"><span>│   └── 有什么阻碍？</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── Sprint Review（Sprint 结束时，≤ 4 小时 / 月 Sprint）</span></span>
<span class="line"><span>│   └── 向利益相关者演示可工作的软件，收集反馈</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── Sprint Retrospective（Review 之后，≤ 3 小时 / 月 Sprint）</span></span>
<span class="line"><span>    └── 团队内部反思：什么做得好？什么可以改进？下个 Sprint 的行动项</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">常见误区</p><ul><li>Daily Scrum 不是&quot;汇报给 Leader&quot;的会议——是团队成员之间的同步，SM 只是旁观引导</li><li>Retrospective 不是&quot;批斗会&quot;——目标是改进流程，不是追责个人</li><li>Sprint Review 不是&quot;演示 PPT&quot;——必须演示<strong>可工作的软件</strong></li></ul></div><h3 id="_2-3-三大工件" tabindex="-1">2.3 三大工件 <a class="header-anchor" href="#_2-3-三大工件" aria-label="Permalink to &quot;2.3 三大工件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工件</th><th>内容</th><th>负责人</th></tr></thead><tbody><tr><td><strong>Product Backlog</strong></td><td>产品的所有需求，按优先级排序，持续演化</td><td>PO</td></tr><tr><td><strong>Sprint Backlog</strong></td><td>当前 Sprint 选中的 Backlog + 任务拆分</td><td>Development Team</td></tr><tr><td><strong>Increment</strong></td><td>Sprint 结束时完成的、可交付的软件增量</td><td>Development Team</td></tr></tbody></table><hr><h2 id="三、kanban-方法" tabindex="-1">三、Kanban 方法 <a class="header-anchor" href="#三、kanban-方法" aria-label="Permalink to &quot;三、Kanban 方法&quot;">​</a></h2><h3 id="_3-1-kanban-的核心原则" tabindex="-1">3.1 Kanban 的核心原则 <a class="header-anchor" href="#_3-1-kanban-的核心原则" aria-label="Permalink to &quot;3.1 Kanban 的核心原则&quot;">​</a></h3><p>Kanban 来自精益生产（丰田生产方式），核心是<strong>可视化工作流</strong>和<strong>限制在制品（WIP，Work In Progress）</strong>。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Kanban 看板示例：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Backlog         开发中 (WIP≤3)     测试中 (WIP≤2)     完成</span></span>
<span class="line"><span>+------------+   +-------------+   +-------------+   +--------+</span></span>
<span class="line"><span>| 需求 H     |   | 需求 E [→]  |   | 需求 C      |   | 需求 A |</span></span>
<span class="line"><span>| 需求 I     |   | 需求 F      |   | 需求 D      |   | 需求 B |</span></span>
<span class="line"><span>| 需求 J     |   | 需求 G      |   |             |   |        |</span></span>
<span class="line"><span>+------------+   +-------------+   +-------------+   +--------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="_3-2-wip-限制的意义" tabindex="-1">3.2 WIP 限制的意义 <a class="header-anchor" href="#_3-2-wip-限制的意义" aria-label="Permalink to &quot;3.2 WIP 限制的意义&quot;">​</a></h3><p>WIP 限制是 Kanban 的核心机制——每个阶段同时进行的任务数量有上限。</p><p><strong>为什么限制 WIP？</strong></p><ul><li>降低上下文切换成本（一个人同时做 3 件事 = 频繁切换 = 效率低）</li><li>暴露瓶颈（&quot;测试中&quot;列满了而&quot;开发中&quot;列有空余 = 测试是瓶颈）</li><li>减少交付周期（完成一件再开始下一件，比并行多件更快）</li></ul><h3 id="_3-3-scrum-vs-kanban" tabindex="-1">3.3 Scrum vs Kanban <a class="header-anchor" href="#_3-3-scrum-vs-kanban" aria-label="Permalink to &quot;3.3 Scrum vs Kanban&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>Scrum</th><th>Kanban</th></tr></thead><tbody><tr><td><strong>节奏</strong></td><td>固定时间盒（Sprint）</td><td>持续流动，无固定周期</td></tr><tr><td><strong>角色</strong></td><td>定义 PO、SM、Team 三个角色</td><td>无强制角色</td></tr><tr><td><strong>变更</strong></td><td>Sprint 内不允许改变 Sprint Backlog</td><td>随时可以变更优先级</td></tr><tr><td><strong>度量</strong></td><td>速率（Velocity）——每个 Sprint 完成的故事点</td><td>交付周期（Lead Time）、吞吐量</td></tr><tr><td><strong>适用场景</strong></td><td>有稳定团队和可规划工作的产品开发</td><td>运维、支持类工作，或需求波动大的场景</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">实践趋势</p><p>绝大多数团队实际使用&quot;<strong>Scrumban</strong>&quot;——以 Scrum 的时间盒和角色为基础，引入 Kanban 的 WIP 限制和可视化看板。</p></div><hr><h2 id="四、用户故事" tabindex="-1">四、用户故事 <a class="header-anchor" href="#四、用户故事" aria-label="Permalink to &quot;四、用户故事&quot;">​</a></h2><h3 id="_4-1-用户故事的标准格式" tabindex="-1">4.1 用户故事的标准格式 <a class="header-anchor" href="#_4-1-用户故事的标准格式" aria-label="Permalink to &quot;4.1 用户故事的标准格式&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>作为 &lt;角色&gt;，</span></span>
<span class="line"><span>我想要 &lt;功能&gt;，</span></span>
<span class="line"><span>以便 &lt;价值/目的&gt;。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>示例：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>作为 注册用户，</span></span>
<span class="line"><span>我想要 通过手机验证码登录，</span></span>
<span class="line"><span>以便 不需要记住复杂的密码也能安全登录。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="_4-2-invest-原则" tabindex="-1">4.2 INVEST 原则 <a class="header-anchor" href="#_4-2-invest-原则" aria-label="Permalink to &quot;4.2 INVEST 原则&quot;">​</a></h3><p>好的用户故事应该满足 INVEST 原则：</p><table tabindex="0"><thead><tr><th>原则</th><th>含义</th><th>反例</th></tr></thead><tbody><tr><td><strong>I</strong>ndependent</td><td>故事之间独立，可以独立开发和测试</td><td>&quot;实现登录&quot;依赖&quot;实现用户注册&quot;</td></tr><tr><td><strong>N</strong>egotiable</td><td>故事是可协商的，不是详细需求文档</td><td>故事中规定了具体的技术方案和 UI 样式</td></tr><tr><td><strong>V</strong>aluable</td><td>对用户或业务有明确价值</td><td>&quot;重构数据访问层&quot;——这是技术任务，不是用户故事</td></tr><tr><td><strong>E</strong>stimable</td><td>团队能够估算故事的工作量</td><td>&quot;研究 AI 推荐算法&quot;——不确定性太高，无法估算</td></tr><tr><td><strong>S</strong>mall</td><td>足够小，能在 1 个 Sprint 内完成</td><td>&quot;构建电商平台&quot;——太大了，需要拆分</td></tr><tr><td><strong>T</strong>estable</td><td>有明确的验收标准，可测试</td><td>&quot;让用户体验更好&quot;——无法测试</td></tr></tbody></table><h3 id="_4-3-用户故事拆分技巧" tabindex="-1">4.3 用户故事拆分技巧 <a class="header-anchor" href="#_4-3-用户故事拆分技巧" aria-label="Permalink to &quot;4.3 用户故事拆分技巧&quot;">​</a></h3><p>将&quot;史诗&quot;（Epic）拆分为可在一个 Sprint 内完成的故事：</p><table tabindex="0"><thead><tr><th>拆分策略</th><th>示例（&quot;用户搜索商品&quot;史诗）</th></tr></thead><tbody><tr><td><strong>按操作拆分</strong></td><td>关键字搜索 → 分类筛选 → 排序</td></tr><tr><td><strong>按数据变体</strong></td><td>搜索有库存商品 → 搜索无库存商品 → 搜索下架商品</td></tr><tr><td><strong>按简单/复杂</strong></td><td>基本搜索 → 高级搜索（多条件组合）</td></tr><tr><td><strong>按平台</strong></td><td>Web 搜索 → 移动端搜索</td></tr></tbody></table><h3 id="_4-4-验收标准-acceptance-criteria" tabindex="-1">4.4 验收标准（Acceptance Criteria） <a class="header-anchor" href="#_4-4-验收标准-acceptance-criteria" aria-label="Permalink to &quot;4.4 验收标准（Acceptance Criteria）&quot;">​</a></h3><p>每个用户故事都应该有清晰的验收标准：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>故事：作为用户，我想要通过手机验证码登录</span></span>
<span class="line"><span></span></span>
<span class="line"><span>验收标准：</span></span>
<span class="line"><span>- [ ] 输入手机号后，点击&quot;获取验证码&quot;，收到含 6 位数字的短信</span></span>
<span class="line"><span>- [ ] 60 秒内不可重复获取验证码</span></span>
<span class="line"><span>- [ ] 输入正确验证码后进入首页</span></span>
<span class="line"><span>- [ ] 输入错误验证码 3 次后锁定 5 分钟</span></span>
<span class="line"><span>- [ ] 未注册的手机号提示&quot;请先注册&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><hr><h2 id="五、sprint-计划与估算" tabindex="-1">五、Sprint 计划与估算 <a class="header-anchor" href="#五、sprint-计划与估算" aria-label="Permalink to &quot;五、Sprint 计划与估算&quot;">​</a></h2><h3 id="_5-1-故事点估算" tabindex="-1">5.1 故事点估算 <a class="header-anchor" href="#_5-1-故事点估算" aria-label="Permalink to &quot;5.1 故事点估算&quot;">​</a></h3><p>故事点（Story Point）是<strong>相对估算</strong>单位——不是&quot;小时&quot;或&quot;人天&quot;，而是相对于一个基准故事的工作量。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>估算刻度：1, 2, 3, 5, 8, 13, 21...（斐波那契数列）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>为什么用斐波那契？</span></span>
<span class="line"><span>- 任务越大，估算的不确定性越高</span></span>
<span class="line"><span>- 13 和 21 之间的差距警告团队：这个任务需要拆分了</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="_5-2-速率-velocity" tabindex="-1">5.2 速率（Velocity） <a class="header-anchor" href="#_5-2-速率-velocity" aria-label="Permalink to &quot;5.2 速率（Velocity）&quot;">​</a></h3><p>速率 = 团队过去几个 Sprint 完成的故事点平均值。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>过去 3 个 Sprint:</span></span>
<span class="line"><span>  Sprint 1: 完成 20 点</span></span>
<span class="line"><span>  Sprint 2: 完成 22 点</span></span>
<span class="line"><span>  Sprint 3: 完成 18 点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>平均速率 = (20 + 22 + 18) / 3 = 20 点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>下一个 Sprint 的容量计划：20 点</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">注意</p><p>速率用于<strong>计划</strong>而非<strong>考核</strong>。不能用速率来比较不同团队的产出——每个团队的估算基准不同，点值没有可比性。</p></div><h3 id="_5-3-sprint-容量规划" tabindex="-1">5.3 Sprint 容量规划 <a class="header-anchor" href="#_5-3-sprint-容量规划" aria-label="Permalink to &quot;5.3 Sprint 容量规划&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>团队：5 人，Sprint 周期：2 周（10 个工作日）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>总容量 = 5 * 10 = 50 人天</span></span>
<span class="line"><span>减去：</span></span>
<span class="line"><span>  - 会议时间（Daily Scrum 15min * 10 + Planning + Review + Retro）≈ 3 天</span></span>
<span class="line"><span>  - 技术债务偿还 / 修复线上问题 ≈ 2 天</span></span>
<span class="line"><span>  - 其他（面试、分享、突发）≈ 2 天</span></span>
<span class="line"><span>实际可用 = 50 - 7 = 43 人天 ≈ 考虑速率后约 20 故事点</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><hr><h2 id="六、持续改进-——-回顾会议" tabindex="-1">六、持续改进 —— 回顾会议 <a class="header-anchor" href="#六、持续改进-——-回顾会议" aria-label="Permalink to &quot;六、持续改进 —— 回顾会议&quot;">​</a></h2><h3 id="_6-1-回顾会议的结构" tabindex="-1">6.1 回顾会议的结构 <a class="header-anchor" href="#_6-1-回顾会议的结构" aria-label="Permalink to &quot;6.1 回顾会议的结构&quot;">​</a></h3><p>回顾会议（Retrospective）是 Scrum 中最重要的会议，是团队自我改进的核心机制。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 设定基调（5 分钟）：建立安全氛围——&quot;这是团队的反思，不是追责&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 收集数据（10 分钟）：这个 Sprint 发生了什么？</span></span>
<span class="line"><span>   - 时间线回顾：Sprint 中发生了哪些关键事件？</span></span>
<span class="line"><span>   - &quot;Start / Stop / Continue&quot;：什么应该开始做 / 停止做 / 继续做？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 分析洞察（15 分钟）：为什么发生了这些事？</span></span>
<span class="line"><span>   - 5 Why 分析法：连续问 5 个&quot;为什么&quot;找到根因</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 决定行动（10 分钟）：下一个 Sprint 要改变什么？</span></span>
<span class="line"><span>   - 选择 1-2 个改进项（不要贪多）</span></span>
<span class="line"><span>   - 明确行动负责人和检查时间</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 结束（5 分钟）：感谢团队，确认行动项</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h3 id="_6-2-5-why-分析法" tabindex="-1">6.2 5 Why 分析法 <a class="header-anchor" href="#_6-2-5-why-分析法" aria-label="Permalink to &quot;6.2 5 Why 分析法&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问题：线上出现了一个数据不一致的 bug</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Why 1: 为什么数据不一致？</span></span>
<span class="line"><span>  → 因为两个服务对同一条数据做了冲突的更新</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Why 2: 为什么两个服务会冲突更新同一条数据？</span></span>
<span class="line"><span>  → 因为我们没有定义这条数据的&quot;归属服务&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Why 3: 为什么没有定义归属？</span></span>
<span class="line"><span>  → 因为在微服务拆分时，数据归属没有被明确讨论</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Why 4: 为什么没有被讨论？</span></span>
<span class="line"><span>  → 因为我们的设计评审 Checklist 中没有&quot;数据归属&quot;这一项</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Why 5: 为什么 Checklist 中没有？</span></span>
<span class="line"><span>  → 因为 Checklist 是两年前定的，之后没有更新过</span></span>
<span class="line"><span></span></span>
<span class="line"><span>根因：设计评审流程缺少定期维护机制</span></span>
<span class="line"><span>改进行动：每季度 Review 并更新设计评审 Checklist</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">5 Why 的要点</p><ol><li>追问到&quot;可行动的根因&quot;为止——不是&quot;人的错误&quot;，而是&quot;流程的漏洞&quot;</li><li>避免&quot;因为他不小心&quot;——这是指责，不是分析</li><li>如果 5 Why 后得出的结论是&quot;加一个审批流程&quot;，那很可能是错误的——好的根因导致<strong>减少流程</strong>而非增加流程</li></ol></div><h3 id="_6-3-改进看板" tabindex="-1">6.3 改进看板 <a class="header-anchor" href="#_6-3-改进看板" aria-label="Permalink to &quot;6.3 改进看板&quot;">​</a></h3><p>将 Retro 产生的改进项可视化，避免&quot;每次 Retro 都在讨论同样的问题&quot;：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>改进看板：</span></span>
<span class="line"><span>  ├── 待开始：引入 API 自动化测试框架</span></span>
<span class="line"><span>  ├── 进行中：建立代码 Review Checklist</span></span>
<span class="line"><span>  ├── 已完成：统一错误码规范</span></span>
<span class="line"><span>  └── 已验收：日志规范落地（已在 2 个 Sprint 中验证有效）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="⭐-面试高频问题" tabindex="-1">⭐ 面试高频问题 <a class="header-anchor" href="#⭐-面试高频问题" aria-label="Permalink to &quot;⭐ 面试高频问题&quot;">​</a></h2><h3 id="q1-敏捷和瀑布模型的核心区别是什么-分别适用什么场景" tabindex="-1">Q1：敏捷和瀑布模型的核心区别是什么？分别适用什么场景？ <a class="header-anchor" href="#q1-敏捷和瀑布模型的核心区别是什么-分别适用什么场景" aria-label="Permalink to &quot;Q1：敏捷和瀑布模型的核心区别是什么？分别适用什么场景？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><table tabindex="0"><thead><tr><th>维度</th><th>瀑布</th><th>敏捷</th></tr></thead><tbody><tr><td><strong>需求处理</strong></td><td>一次性确定，冻结变更</td><td>迭代演化，欢迎变化</td></tr><tr><td><strong>反馈循环</strong></td><td>项目尾声才有用户反馈</td><td>每个 Sprint 获取反馈</td></tr><tr><td><strong>风险暴露</strong></td><td>集中在后期</td><td>持续暴露，早期化解</td></tr><tr><td><strong>交付方式</strong></td><td>最终一次性交付</td><td>持续增量交付</td></tr></tbody></table><ul><li><strong>瀑布适用</strong>：需求极其明确且不会变化（航天嵌入式软件、核电站控制系统），错误的代价远大于需求变更的成本</li><li><strong>敏捷适用</strong>：需求不确定或快速变化（互联网产品、创业项目），快速验证比完美实现更重要</li></ul><p><strong>面试金句</strong>：&quot;瀑布适合&#39;盖大桥&#39;——需求明确、变更成本高。敏捷适合&#39;做产品&#39;——你不知道用户真正想要什么，需要通过持续交付和反馈来探索。&quot;</p><h3 id="q2-scrum-的三个角色分别是什么-各自的职责是什么" tabindex="-1">Q2：Scrum 的三个角色分别是什么？各自的职责是什么？ <a class="header-anchor" href="#q2-scrum-的三个角色分别是什么-各自的职责是什么" aria-label="Permalink to &quot;Q2：Scrum 的三个角色分别是什么？各自的职责是什么？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><ul><li><strong>Product Owner（PO）</strong>：回答&quot;做什么&quot;——管理 Product Backlog 优先级，定义验收标准，是产品的最终负责人</li><li><strong>Scrum Master（SM）</strong>：回答&quot;如何高效&quot;——确保 Scrum 流程被正确执行，消除团队障碍，引导会议，是教练和仆人式领导者</li><li><strong>Development Team</strong>：回答&quot;如何做&quot;——自组织地完成 Sprint 目标，交付可工作的软件增量，5-9 人</li></ul><p><strong>关键区分</strong>：PO 不是&quot;提需求的人&quot;，SM 不是&quot;项目经理&quot;，Development Team 不是&quot;被分配任务的资源&quot;。</p><h3 id="q3-一个-sprint-中-需求可以变更吗" tabindex="-1">Q3：一个 Sprint 中，需求可以变更吗？ <a class="header-anchor" href="#q3-一个-sprint-中-需求可以变更吗" aria-label="Permalink to &quot;Q3：一个 Sprint 中，需求可以变更吗？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><p>不能。一旦 Sprint Backlog 在 Sprint Planning 中被确认，<strong>Sprint 期间不允许变更</strong>。这是 Scrum 的核心规则——给团队一个不受干扰的专注期。</p><p>但 Sprint 之间可以任意变更——上一个 Sprint 完成后，下一个 Sprint Planning 中 PO 可以根据最新情况重新排列 Backlog 优先级。</p><div class="tip custom-block"><p class="custom-block-title">如果确实需要变更</p><p>两种选择：</p><ol><li><strong>紧急变更</strong>：PO 可以宣布终止当前 Sprint（极少使用），启动新的 Sprint Planning</li><li><strong>等待</strong>：将新需求放入 Product Backlog 顶部，下一个 Sprint 优先处理</li></ol></div><h3 id="q4-故事点和人天有什么区别-为什么用故事点估算" tabindex="-1">Q4：故事点和人天有什么区别？为什么用故事点估算？ <a class="header-anchor" href="#q4-故事点和人天有什么区别-为什么用故事点估算" aria-label="Permalink to &quot;Q4：故事点和人天有什么区别？为什么用故事点估算？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><table tabindex="0"><thead><tr><th>维度</th><th>故事点</th><th>人天</th></tr></thead><tbody><tr><td><strong>性质</strong></td><td>相对估算（相对于基准故事）</td><td>绝对估算</td></tr><tr><td><strong>反映</strong></td><td>工作量 + 复杂度 + 不确定性</td><td>仅反映时间</td></tr><tr><td><strong>团队差异</strong></td><td>不同团队的&quot;1 点&quot;含义不同</td><td>&quot;1 天&quot;理论上跨团队一致</td></tr><tr><td><strong>准确度</strong></td><td>团队一致时准确度高</td><td>总是偏乐观</td></tr><tr><td><strong>优势</strong></td><td>避免&quot;这个任务 3 天就能搞定&quot;的盲目自信</td><td>直观，非技术人员也能理解</td></tr></tbody></table><p><strong>为什么用故事点</strong>：人天估算有锚定效应（&quot;一个页面开发需要 3 天&quot;——但实际上不同的&quot;页面&quot;复杂度可能差 10 倍），且人天估算忽略了复杂度和不确定性。故事点通过相对比较（&quot;这个页面比上次那个复杂 2 倍&quot;）得到更准确的估算。</p><h3 id="q5-你们团队如何进行-sprint-计划" tabindex="-1">Q5：你们团队如何进行 Sprint 计划？ <a class="header-anchor" href="#q5-你们团队如何进行-sprint-计划" aria-label="Permalink to &quot;Q5：你们团队如何进行 Sprint 计划？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><ol><li><strong>PO 提前准备</strong>：PO 在 Planning 前已经按优先级排序好 Backlog，Top 部分有清晰的验收标准</li><li><strong>容量确认</strong>：根据团队速率（过去 3 个 Sprint 的平均故事点）和可用人天，确定本 Sprint 容量</li><li><strong>讲解与澄清</strong>：PO 逐条讲解顶部 Backlog 的需求和验收标准，团队提问澄清</li><li><strong>估算</strong>：团队对每个 Story 进行故事点估算（Planning Poker 或 T-shirt Sizing）</li><li><strong>选择与承诺</strong>：团队按优先级从 Backlog 中选取，直到达到容量上限</li><li><strong>任务拆分</strong>：将选中的 Story 拆分为技术任务（每个人 &lt; 1 天的粒度）</li><li><strong>输出</strong>：Sprint Goal + Sprint Backlog（Story + Task）</li></ol><h3 id="q6-如果团队速率-velocity-不稳定-应该怎么办" tabindex="-1">Q6：如果团队速率（Velocity）不稳定，应该怎么办？ <a class="header-anchor" href="#q6-如果团队速率-velocity-不稳定-应该怎么办" aria-label="Permalink to &quot;Q6：如果团队速率（Velocity）不稳定，应该怎么办？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><p>速率不稳定是正常现象——新团队形成期、需求类型变化、团队成员变动都会导致速率震荡。</p><p>应对策略：</p><ol><li><strong>使用滚动平均</strong>：用过去 3 个 Sprint 的平均速率，而非上一 Sprint 的速率</li><li><strong>分析变异来源</strong>：是估算不准还是外部干扰？——不同原因不同对策</li><li><strong>引入缓冲区</strong>：计划时留 10%-15% 的缓冲（处理突发线上问题、技术债务）</li><li><strong>关注趋势而非单点</strong>：速率是逐渐上升还是持续下降？趋势比绝对值更重要</li><li><strong>拆分大故事</strong>：点数过大的 Story（&gt; 13 点）估算极不准，拆分后稳定性会提升</li></ol><p><strong>根本原则</strong>：速率是<strong>计划辅助工具</strong>，不是考核指标。不要用速率衡量团队效率——这会催生&quot;点值通胀&quot;。</p><h3 id="q7-retro-回顾会议如果大家都不发言怎么办" tabindex="-1">Q7：Retro 回顾会议如果大家都不发言怎么办？ <a class="header-anchor" href="#q7-retro-回顾会议如果大家都不发言怎么办" aria-label="Permalink to &quot;Q7：Retro 回顾会议如果大家都不发言怎么办？&quot;">​</a></h3><p><strong>标准答案</strong>：这是常见的 Retro 困境，通常是因为心理安全感不足或会议形式单一。</p><p>对策：</p><ol><li><strong>改变会议形式</strong>：用&quot;写便签再匿名投票&quot;代替公开发言，降低发言门槛</li><li><strong>设定基调</strong>：SM 在会议开始时明确&quot;这不是追责会，是改进会&quot;</li><li><strong>分组讨论</strong>：5 人以上团队分成 2-3 人的小组先讨论，再汇总</li><li><strong>使用数据</strong>：从 Jira 拉数据——&quot;本 Sprint 有 3 个故事被带回了 Backlog，这是为什么？&quot;——用数据引导讨论</li><li><strong>Leader 后发言</strong>：Tech Lead 和 SM 先沉默，让团队成员先说，避免&quot;领导定调&quot;</li></ol><h3 id="q8-敏捷转型中常见的失败原因有哪些" tabindex="-1">Q8：敏捷转型中常见的失败原因有哪些？ <a class="header-anchor" href="#q8-敏捷转型中常见的失败原因有哪些" aria-label="Permalink to &quot;Q8：敏捷转型中常见的失败原因有哪些？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><ol><li><strong>&quot;伪敏捷&quot;</strong>：用了 Daily Scrum 和 Jira 就叫敏捷了，但本质依然是瀑布思维——需求不欢迎变化、不重视反馈</li><li><strong>Leadership 不支持</strong>：管理层嘴上说敏捷，实际上还是在要求&quot;保质保量按期交付&quot;，团队没有真正的自治权</li><li><strong>忽视工程技术</strong>：敏捷不只是&quot;站会 + 看板&quot;，TDD、CI/CD、重构等工程实践是敏捷的基础</li><li><strong>Retro 流于形式</strong>：每次都讨论同样的问题但从不落地改进，丧失信任</li><li><strong>团队太大</strong>：超过 9 人的团队沟通成本急剧上升，敏捷实践难以运转</li></ol><p><strong>一句话总结</strong>：敏捷转型失败的最大原因是——<strong>只改了流程，没改变思维</strong>。</p>`,109)])])}const h=s(r,[["render",p]]);export{b as __pageData,h as default};
